import React, { forwardRef } from 'react';
import { clsx } from 'clsx';
import { Icon, type IconName } from '../Icon';
import { pyxisPart } from '../../utils/parts';
import './Input.css';

export type InputProps = Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size'> & {
  /** Label text */
  label?: string;
  /** Hint text shown below the input */
  hint?: string;
  /** Error message — turns input red and shows message */
  error?: string;
  /** Icon to show inside the input */
  icon?: IconName;
  /** Icon position. Default: 'left' */
  iconPosition?: 'left' | 'right';
};

/**
 * A text input field.
 *
 * ```tsx
 * <Input label="Artist name" placeholder="Enter artist name" />
 * <Input label="Email" type="email" error="Invalid email address" />
 * ```
 */
export const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      label,
      hint,
      error,
      icon,
      iconPosition = 'left',
      className,
      id,
      ...rest
    },
    ref
  ) => {
    const inputId = id ?? `input-${Math.random().toString(36).slice(2)}`;
    const hasError = !!error;

    return (
      <div className={clsx('pyxis-field', className)} {...pyxisPart('input')}>
        {label && (
          <label
            htmlFor={inputId}
            className="pyxis-field__label"
            data-has-error={hasError ? 'true' : undefined}
            {...pyxisPart('input', 'label')}
          >
            {label}
          </label>
        )}
        <div
          className="pyxis-field__input-wrap"
          data-icon={icon ? iconPosition : undefined}
          data-has-error={hasError ? 'true' : undefined}
          {...pyxisPart('input', 'control-shell')}
        >
          {icon && iconPosition === 'left' && (
            <span className="pyxis-field__icon" aria-hidden {...pyxisPart('input', 'icon')}>
              <Icon name={icon} size={14} />
            </span>
          )}
          <input
            ref={ref}
            id={inputId}
            className="pyxis-field__input"
            aria-invalid={hasError}
            aria-describedby={
              hasError ? `${inputId}-error` : hint ? `${inputId}-hint` : undefined
            }
            {...pyxisPart('input', 'control')}
            {...rest}
          />
          {icon && iconPosition === 'right' && (
            <span className="pyxis-field__icon" aria-hidden {...pyxisPart('input', 'icon')}>
              <Icon name={icon} size={14} />
            </span>
          )}
        </div>
        {hasError && (
          <span id={`${inputId}-error`} className="pyxis-field__message" data-status="error" {...pyxisPart('input', 'error')}>
            {error}
          </span>
        )}
        {!hasError && hint && (
          <span id={`${inputId}-hint`} className="pyxis-field__message" {...pyxisPart('input', 'hint')}>
            {hint}
          </span>
        )}
      </div>
    );
  }
);
Input.displayName = 'Input';
